def fmt_usd(v):  return f"${v:,.0f}"
def fmt_pct(v):  return f"{v:.1%}"
def fmt_days(v): return f"{v:.1f} days" if v else "—"
def sec(t):      st.markdown(f'<p class="sec">{t}</p>', unsafe_allow_html=True)

CHART = dict(plot_bgcolor="#f8fbff", paper_bgcolor="#f8fbff",
             font=dict(color="#5a7898", size=11, family="Inter, sans-serif"),
             margin=dict(t=44,b=26,l=8,r=8),
             legend=dict(orientation="h",yanchor="bottom",y=1.02,font=dict(size=10)))
GRID = dict(gridcolor="#e4eef8", zeroline=False)

def clayout(title, height=300, **kw):
    b = dict(**CHART, title=dict(text=title, font=dict(size=13,color="#0d2040")),
             height=height, xaxis=GRID, yaxis=dict(**GRID))
    b.update(kw); return b

def risk_level(cov_ratio, expiry_days, sl):
    """Return LOW / MEDIUM / HIGH based on business rules."""
    if cov_ratio < 0.5 or (expiry_days and expiry_days < 5) or sl < 0.75:
        return "HIGH"
    if cov_ratio < 1.0 or (expiry_days and expiry_days < 14) or sl < 0.90:
        return "MEDIUM"
    return "LOW"

def risk_badge(level):
    cls = {"LOW":"risk-low","MEDIUM":"risk-medium","HIGH":"risk-high"}.get(level,"risk-low")
    return f'<span class="{cls}">{level} RISK</span>'

def coverage_days(qty, avg_daily_demand):
    if avg_daily_demand <= 0: return None
    return qty / avg_daily_demand

def plain_action(action_str, mid=None):
    """Convert technical action string to plain English.
    Always translates material IDs and supplier IDs to human-readable names.
    Input:  'Procure 93 × DIAG_CRIT02 from SUP_MERIL ($41,069)'
    Output: 'Order 93 units of Troponin I Antibody (Cardiac) from Meril Life Sciences'
    """
    name = pname(mid) if mid else ""
    if "Do Nothing" in action_str or "DoNothing" in action_str:
        return "No action needed — maintain current stock levels"

    if "Procure" in action_str:
        try:
            qty     = action_str.split("Procure")[1].split("×")[0].strip()
            # Extract the raw material ID from between × and "from"
            raw_mid = action_str.split("×")[1].split("from")[0].strip() if "×" in action_str else ""
            # Extract the raw supplier ID from after "from" (before the cost in brackets)
            raw_sup = action_str.split("from")[-1].split("(")[0].strip() if "from" in action_str else ""
            # Translate both to human names
            prod = pname(raw_mid) if raw_mid else (name or raw_mid or "product")
            sup  = sname(raw_sup) if raw_sup in SUPPLIER_NAMES else raw_sup
            return f"Order {qty} units of {prod} from {sup}"
        except Exception:
            return f"Place procurement order for {name}" if name else action_str

    if "Transfer" in action_str:
        try:
            # Format: "Transfer 292 × DIAG_STD02: LOC_MUM → LOC_DEL"
            qty_part = action_str.split("Transfer")[1].split("×")[0].strip()
            raw_mid  = action_str.split("×")[1].split(":")[0].strip() if "×" in action_str else ""
            src_raw  = action_str.split(":")[1].split("→")[0].strip() if ":" in action_str else ""
            dst_raw  = action_str.split("→")[-1].strip() if "→" in action_str else ""
            prod = pname(raw_mid) if raw_mid else (name or "product")
            src  = lname(src_raw) if src_raw in LOCATION_NAMES else src_raw
            dst  = lname(dst_raw) if dst_raw in LOCATION_NAMES else dst_raw
            return f"Move {qty_part} units of {prod} from {src} to {dst}"
        except Exception:
            return f"Transfer stock between warehouses for {name}" if name else action_str

    if "Expire" in action_str or "Dispose" in action_str:
        try:
            # Format: "Dispose 38 expiring units of DIAG_CRIT02 @ LOC_MUM"
            raw_mid = action_str.split("of")[-1].split("@")[0].strip() if "of" in action_str else ""
            prod = pname(raw_mid) if raw_mid else (name or "product")
            return f"Dispose of expiring {prod} stock to prevent write-off losses"
        except Exception:
            return f"Dispose of expiring stock of {name}" if name else action_str

    return action_str

def plain_reasoning(action_str, risk_sc, cost, autonomy, mid=None, exp_days=None, cov=None):
    """Generate executive-friendly reasoning — no technical jargon."""
    name = pname(mid) if mid else "this product"
    if "DoNothing" in action_str or "Do Nothing" in action_str:
        return (f"All products are currently within safe stock levels. "
                f"Demand forecasts are stable and no immediate procurement or transfers "
                f"are cost-effective. The system recommends holding the current position.")
    if "Procure" in action_str:
        base = (f"Stock levels for <strong>{name}</strong> are running low "
                f"and are expected to fall below the minimum safety threshold within the "
                f"planning window. ")
        if exp_days and exp_days < 10:
            base += (f"Additionally, the existing lot expires in {exp_days} days, "
                     f"making replenishment even more urgent. ")
        if autonomy in ("ESCALATE","ALERT_AND_WAIT"):
            base += (f"Given the procurement cost of {fmt_usd(cost)}, "
                     f"human approval is required before placing this order. "
                     f"Delaying beyond 24 hours increases the stockout risk significantly.")
        else:
            base += (f"This order has been placed automatically within pre-approved "
                     f"spending limits to prevent a stockout and protect service levels.")
        return base
    if "Transfer" in action_str:
        return (f"One warehouse holds more stock than it needs, while another is "
                f"running low on <strong>{name}</strong>. Moving stock between locations "
                f"costs far less than placing a new order and resolves the imbalance "
                f"immediately without involving a supplier.")
    if "Expire" in action_str or "Dispose" in action_str:
        return (f"A batch of <strong>{name}</strong> will expire within 3 days. "
                f"Disposing of it now prevents a larger financial write-off when it "
                f"automatically expires and clears space for fresher stock.")
    return f"Recommended action based on current stock levels and 7-day demand outlook for {name}."

def executive_summary(state, sl, exp_units):
    """Generate 2-3 line plain-English summary of current situation."""
    items_list = []
    for mid, items in state.inventory.items():
        total = sum(i.quantity for i in items)
        safe  = sum(i.safety_stock for i in items)
        hist  = state.demand_history.get(mid,[])
        avg_d = float(np.mean(hist[-30:])) if hist else 1
        cov   = coverage_days(total, avg_d)
        if total < safe:
            items_list.append((pname(mid), cov, "below_safe"))
    exp_items = []
    for mid, items in state.inventory.items():
        for it in items:
            if it.expiry_days is not None and 0 < it.expiry_days <= 7:
                exp_items.append(pname(mid)); break

    parts = []
    if sl >= 0.95:
        parts.append("Service levels are <strong>healthy</strong> across all products.")
    elif sl >= 0.80:
        parts.append("Service levels are <strong>moderately healthy</strong> but warrant monitoring.")
    else:
        parts.append("<strong>Service levels are below target</strong> — immediate attention needed.")
    if items_list:
        names = ", ".join(n for n,_,_ in items_list[:2])
        suffix = f" and {len(items_list)-2} more" if len(items_list)>2 else ""
        parts.append(f"<strong>{names}{suffix}</strong> are below safety stock levels.")
    if exp_items:
        names = ", ".join(exp_items[:2])
        parts.append(f"<strong>{names}</strong> are expiring within 7 days — action recommended.")
    if not items_list and not exp_items and sl >= 0.95:
        parts.append("No immediate interventions are required. Continue monitoring.")
    return " ".join(parts)


