def build_email(action, reasoning_html, risk_sc, cost, cov_days_val,
                day, scope, resolved, resolved_at):
    now  = datetime.now().strftime("%d %b %Y, %H:%M")
    plain_act = plain_action(action)
    if resolved == "Approved":
        status = '<span class="email-status es-approved">APPROVED</span>'
    elif resolved == "Rejected":
        status = '<span class="email-status es-rejected">REJECTED</span>'
    else:
        status = '<span class="email-status es-pending">AWAITING APPROVAL</span>'

    risk_lbl = ("HIGH" if risk_sc < -5000 else "MEDIUM" if risk_sc < 0 else "LOW")
    return f"""
<div class="email-outer">
  <div class="email-head">
    <div class="email-field"><b>To:</b> supply-chain-manager@biotech.com</div>
    <div class="email-field"><b>From:</b> supply-chain-agent@biotech.com</div>
    <div class="email-field"><b>Date:</b> {now} &nbsp;·&nbsp; Day {day}</div>
    <div class="email-subject">Action Required: Procurement Decision — {scope} {status}</div>
  </div>
  <div class="email-body">
    <p>Our supply chain planning system has identified an action that requires
    your approval before it can be executed.</p>
    <div class="email-sec-lbl" style="margin-top:14px">Recommended Action</div>
    <p><strong>{plain_act}</strong></p>
    <div class="email-sec-lbl" style="margin-top:14px">Summary</div>
    <table class="email-tbl">
      <tr><td>Estimated cost</td><td>{fmt_usd(cost)}</td></tr>
      <tr><td>Risk level</td><td>{risk_lbl}</td></tr>
      <tr><td>Stock coverage after action</td>
          <td>{fmt_days(cov_days_val) if cov_days_val else "—"}</td></tr>
      <tr><td>Scope</td><td>{scope}</td></tr>
    </table>
    <div class="email-sec-lbl" style="margin-top:14px">Why This Action Is Recommended</div>
    <p>{reasoning_html}</p>
    <div class="email-sec-lbl" style="margin-top:14px">What Happens Next</div>
    <p>Please approve or reject this request in the dashboard.
    If no response is received within 4 hours, your team lead will be notified.</p>
  </div>
  <div class="email-foot">
    Automated message · Supply Chain AI Agent · All decisions logged to audit trail
  </div>
</div>"""


