#  TAB 4 — EVENTS & ALERTS
# ═════════════════════════════════════════════════════════════════════════════
with tab_events:
    _ev1, _ev2 = st.columns(2, gap="large")

    with _ev1:
        sec("Active Market Events")
        st.caption("Events currently influencing demand forecasts.")
        if not state.market_events:
            st.markdown('<div class="al al-blue">No active events. '
                        'Use the sidebar to inject a market event.</div>',
                        unsafe_allow_html=True)
        else:
            for ev in state.market_events:
                _change=(ev.multiplier-1)*100
                _sign="+" if _change>=0 else ""
                _cls="al-amber" if abs(_change)>30 else "al-blue"
                st.markdown(
                    f'<div class="al {_cls}">'
                    f'<strong>{elabel(ev.event_type)}</strong> — {pname(ev.material_id)}<br>'
                    f'Demand impact: <strong>{_sign}{_change:.0f}%</strong> '
                    f'for <strong>{ev.duration_days} days</strong></div>',
                    unsafe_allow_html=True)

    with _ev2:
        sec("Event History")
        st.caption("Log of all events created in this session.")
        if not st.session_state.event_log:
            st.markdown('<div class="al al-blue">No events created yet.</div>',
                        unsafe_allow_html=True)
        else:
            st.dataframe(pd.DataFrame(st.session_state.event_log),
                         use_container_width=True, hide_index=True)

    # Expiry risk section
    st.markdown("")
    sec("Expiry Risk Monitor")
    _er3=[{"Product":pname(mid),"Warehouse":lname(it.location),
           "Expiry in (days)":it.expiry_days,"Units at Risk":int(it.quantity)}
          for mid,its in state.inventory.items()
          for it in its if it.expiry_days is not None and it.expiry_days<=14]
    if _er3:
        _erdf=pd.DataFrame(_er3).sort_values("Expiry in (days)")
        st.dataframe(_erdf, use_container_width=True, hide_index=True)
        _fig_exp=px.bar(_erdf,x="Product",y="Units at Risk",color="Expiry in (days)",
                        color_continuous_scale="RdYlGn_r",
                        title="Units Expiring Within 14 Days by Product")
        _fig_exp.update_layout(**clayout("",height=280))
        st.plotly_chart(_fig_exp,use_container_width=True)
    else:
        st.markdown('<div class="al al-green">No products expiring within 14 days. '
                    'Expiry risk is under control.</div>', unsafe_allow_html=True)


# ═════════════════════════════════════════════════════════════════════════════
#  TAB 5 — AGENT MEMORY & DECISION INTELLIGENCE
# ═════════════════════════════════════════════════════════════════════════════
with tab_memory:
    _mem = load_agent_memory("data/inventory.db")
    _rh  = st.session_state.reward_history

    # ── Summary stat cards ────────────────────────────────────────────────────
    sec("Agent Intelligence Summary")
    st.caption("A complete record of every decision the AI has made — what it did, why, and what happened.")

    _total_dec  = len(_mem) + len(st.session_state.cycle_log)
    _auto_dec   = sum(1 for m in _mem if m.get("autonomy") == "AUTO_EXECUTE")
    _esc_dec    = sum(1 for m in _mem if m.get("autonomy") in ("ALERT_AND_WAIT","ESCALATE"))
    _avg_reward = float(np.mean(_rh)) if _rh else 0

    _ms1, _ms2, _ms3, _ms4 = st.columns(4)
    _ms1.metric("Total Decisions", _total_dec,
                help="Every planning cycle the agent has completed")
    _ms2.metric("Auto-Executed",   _auto_dec,
                help="Actions taken autonomously within approved limits")
    _ms3.metric("Sent for Approval", _esc_dec,
                help="High-cost decisions that required human sign-off")
    _ms4.metric("Avg Cycle Impact",  fmt_usd(abs(_avg_reward)),
                delta="positive" if _avg_reward >= 0 else "negative",
                delta_color="normal" if _avg_reward >= 0 else "inverse",
                help="Average financial impact per planning cycle")

    st.markdown("")

    if not _mem and not st.session_state.cycle_log:
        st.markdown(
            '<div class="al al-blue" style="padding:24px;text-align:center">'
            '<strong>Agent memory is empty.</strong><br><br>'
            'Run planning cycles to build the decision history. '
            'Every action the agent takes is recorded here with full reasoning '
            'for compliance, audit, and continuous improvement.</div>',
            unsafe_allow_html=True)
    else:
        # ── THREE-COLUMN CHARTS ROW ───────────────────────────────────────────
        _mc1, _mc2, _mc3 = st.columns(3, gap="large")

        with _mc1:
            sec("Financial Impact per Cycle")
            if len(_rh) >= 2:
                _cycles = list(range(1, len(_rh) + 1))
                _roll3  = pd.Series(_rh).rolling(3, min_periods=1).mean().tolist()
                _fig_m1 = go.Figure()
                _fig_m1.add_trace(go.Bar(
                    x=_cycles, y=_rh, name="Reward",
                    marker_color=["#2e8b57" if r >= 0 else "#A1594B" for r in _rh],
                    opacity=0.55))
                _fig_m1.add_trace(go.Scatter(
                    x=_cycles, y=_roll3, mode="lines",
                    line=dict(color="#62A5CD", width=2.5), name="3-cycle trend"))
                _fig_m1.add_hline(y=0, line_dash="dash", line_color="#94A7B4", line_width=1)
                _fig_m1.update_layout(**clayout("", height=240))
                _fig_m1.update_layout(
                    xaxis=dict(**GRID, title="Cycle #"),
                    yaxis=dict(**GRID, title="Impact ($)"))
                st.plotly_chart(_fig_m1, use_container_width=True)
                _improving = len(_rh) >= 3 and np.mean(_rh[-3:]) > np.mean(_rh[:max(3,len(_rh)//2)])
                st.caption("Trend: " + ("improving over time" if _improving else "stable / variable"))
            else:
                st.caption("Run 2+ cycles to see financial trend")

        with _mc2:
            sec("How the Agent Makes Decisions")
            if _mem:
                _mdf_au = pd.DataFrame(_mem)
                _au_counts = _mdf_au["autonomy"].value_counts().reset_index()
                _au_counts.columns = ["Autonomy", "Count"]
                _label_map = {
                    "AUTO_EXECUTE":   "Auto-executed",
                    "ALERT_AND_WAIT": "Sent for approval",
                    "ESCALATE":       "Escalated",
                    "HUMAN_APPROVED": "Human approved",
                    "MANUAL":         "Manual",
                }
                _au_counts["Autonomy"] = _au_counts["Autonomy"].map(
                    lambda x: _label_map.get(x, x))
                _fig_m2 = px.pie(
                    _au_counts, names="Autonomy", values="Count",
                    color="Autonomy",
                    color_discrete_map={
                        "Auto-executed":      "#2e8b57",
                        "Sent for approval":  "#F19341",
                        "Escalated":          "#A1594B",
                        "Human approved":     "#62A5CD",
                        "Manual":             "#112341",
                    },
                    hole=0.5)
                _fig_m2.update_traces(textposition="outside", textfont_size=11)
                _fig_m2.update_layout(
                    height=240, paper_bgcolor="#f8fbff",
                    font=dict(color="#4a6580"),
                    margin=dict(t=10, b=10),
                    legend=dict(font=dict(size=10), orientation="v"))
                st.plotly_chart(_fig_m2, use_container_width=True)
                _auto_pct = _auto_dec / max(len(_mem), 1) * 100
                st.caption(f"{_auto_pct:.0f}% of decisions executed fully automatically")
            else:
                st.caption("Autonomy breakdown appears after first cycles")

        with _mc3:
            sec("Monte Carlo Forecast Accuracy")
            if len(_rh) >= 3:
                # Show how reward volatility changes — proxy for forecast improving
                _roll_std = pd.Series(_rh).rolling(3, min_periods=2).std().fillna(0).tolist()
                _cycles3  = list(range(1, len(_rh) + 1))
                _fig_m3   = go.Figure()
                _fig_m3.add_trace(go.Scatter(
                    x=_cycles3, y=_roll_std,
                    mode="lines+markers", name="Reward volatility",
                    line=dict(color="#F19341", width=2.5),
                    fill="tozeroy", fillcolor="rgba(241,147,65,.10)",
                    marker=dict(size=5)))
                _fig_m3.update_layout(**clayout("", height=200))
                _fig_m3.update_layout(
                    xaxis=dict(**GRID, title="Cycle"),
                    yaxis=dict(**GRID, title="Volatility ($)"))
                st.plotly_chart(_fig_m3, use_container_width=True)
                st.caption("Lower volatility over time = more predictable, stable outcomes")
            else:
                # Show scenario distribution from latest forecast instead
                if _mem:
                    _fig_m3b = go.Figure()
                    _sample_rewards = [m.get("reward", 0) for m in _mem if m.get("reward")]
                    if _sample_rewards:
                        _fig_m3b.add_trace(go.Histogram(
                            x=_sample_rewards, nbinsx=12,
                            marker_color="#62A5CD", opacity=0.7, name="Reward dist"))
                        _fig_m3b.update_layout(**clayout("", height=200,
                            xaxis=dict(**GRID, title="Reward ($)"),
                            yaxis=dict(**GRID, title="Frequency")))
                        st.plotly_chart(_fig_m3b, use_container_width=True)
                        st.caption("Distribution of rewards across all past decisions")
                else:
                    st.caption("Runs 3+ cycles to see forecast accuracy trend")

        st.markdown("")

        # ── NARRATIVE DECISION LOG ────────────────────────────────────────────
        sec("Decision Log — What Happened and Why")
        st.caption(
            "Every AI decision in plain English. "
            "Use this tab for stakeholder briefings, compliance audits, or to "
            "understand why the system made a particular call."
        )

        _log_source = list(reversed(_mem)) if _mem else []
        if not _log_source and st.session_state.cycle_log:
            # Fall back to session log
            for cl in reversed(st.session_state.cycle_log):
                st.markdown(
                    f'<div style="background:#fff;border:1px solid #dde4ee;'
                    f'border-radius:10px;padding:14px 18px;margin:8px 0;'
                    f'box-shadow:0 1px 4px rgba(10,30,60,.04)">'
                    f'<div style="font-weight:600;color:#112341;margin-bottom:4px">'
                    f'Day {cl.get("Day","—")} &nbsp;·&nbsp; {cl.get("Action","—")}</div>'
                    f'<div style="font-size:.8rem;color:#94A7B4">'
                    f'Outcome: {cl.get("Impact","—")} &nbsp;·&nbsp; {cl.get("Autonomy","—")}'
                    f'</div></div>', unsafe_allow_html=True)
        else:
            for row in _log_source:
                _aut     = str(row.get("autonomy", ""))
                _aut_lbl = {
                    "AUTO_EXECUTE":   "Executed automatically",
                    "ALERT_AND_WAIT": "Sent for approval",
                    "ESCALATE":       "Escalated to manager",
                    "HUMAN_APPROVED": "Human approved",
                    "MANUAL":         "Manual execution",
                }.get(_aut, _aut)
                _r       = float(row.get("reward", 0))
                _cost    = float(row.get("cost", 0))
                _rs      = float(row.get("risk_score", 0))
                _rl_val  = "LOW" if _rs > 0 else "MEDIUM" if _rs > -5000 else "HIGH"
                _a_plain = plain_action(str(row.get("action", "")))
                _reason  = str(row.get("reasoning", "No reasoning recorded."))[:280]
                _pill_cls_mem = (
                    "pill-green"  if _aut == "AUTO_EXECUTE" else
                    "pill-amber"  if _aut in ("ALERT_AND_WAIT", "ESCALATE") else
                    "pill-blue"
                )
                _impact_col = "#16a34a" if _r >= 0 else "#dc2626"
                st.markdown(
                    f'<div style="background:#fff;border:1px solid #dde4ee;'
                    f'border-radius:12px;padding:18px 20px;margin:8px 0;'
                    f'box-shadow:0 1px 6px rgba(10,30,60,.05)">'
                    # header row
                    f'<div style="display:flex;justify-content:space-between;'
                    f'align-items:center;margin-bottom:10px">'
                    f'<div style="font-weight:700;color:#112341;font-size:.88rem">'
                    f'Day {row.get("day", "—")}</div>'
                    f'<span class="pill {_pill_cls_mem}" style="font-size:.7rem">'
                    f'{_aut_lbl}</span>'
                    f'</div>'
                    # what happened
                    f'<div style="font-size:.83rem;margin-bottom:8px">'
                    f'<span style="color:#94A7B4;font-size:.7rem;text-transform:uppercase;'
                    f'letter-spacing:.08em">What happened</span><br>'
                    f'<span style="color:#0d2040;font-weight:500">{_a_plain}</span>'
                    f'</div>'
                    # why
                    f'<div style="font-size:.82rem;color:#3a5270;margin-bottom:10px;'
                    f'line-height:1.65;padding:10px 14px;background:#ffffff;'
                    f'border-radius:6px;border-left:3px solid #93c5fd">'
                    f'<span style="color:#94A7B4;font-size:.68rem;text-transform:uppercase;'
                    f'letter-spacing:.08em;display:block;margin-bottom:4px">Why</span>'
                    f'{_reason}{"..." if len(str(row.get("reasoning", ""))) > 280 else ""}'
                    f'</div>'
                    # outcome row
                    f'<div style="display:flex;gap:16px;font-size:.78rem;color:#94A7B4">'
                    f'<span>Risk level: <strong style="color:#112341">{_rl_val}</strong></span>'
                    f'<span>Financial impact: '
                    f'<strong style="color:{_impact_col}">'
                    f'{"+" if _r >= 0 else ""}{fmt_usd(_r)}</strong></span>'
                    f'<span>Cost of action: <strong style="color:#112341">{fmt_usd(_cost)}</strong></span>'
                    f'</div>'
                    f'</div>',
                    unsafe_allow_html=True)

        # Clear button
        st.markdown("")
        if st.button("Clear Decision History"):
            _cn = sqlite3.connect("data/inventory.db")
            _cn.execute("DELETE FROM agent_memory")
            _cn.commit(); _cn.close()
            st.session_state.cycle_log    = []
            st.session_state.reward_history = []
            st.rerun()


# ─────────────────────────────────────────────────────────────────────────────
st.markdown("---")
st.caption(
    "Supply Chain Decision Intelligence  ·  "
    "AI Planning Engine  ·  Human-in-the-loop  ·  "
    f"Day {state.current_day}"
)